node - <<'NODE'
const fs = require('fs');
const path = require('path');
const AdmZip = require('adm-zip');
(async () => {
  const dest = '/Users/yin/.codex/skills/pageel-para-skills-para-skill';
  if (fs.existsSync(dest)) throw new Error('Destination already exists: ' + dest);
  const { MarketSDK } = await import('./node_modules/@lobehub/market-sdk/dist/index.mjs');
  const creds = JSON.parse(fs.readFileSync('/Users/yin/.lobehub-market/user-credentials.json','utf8'));
  const sdk = new MarketSDK({ baseURL: creds.baseUrl, accessToken: creds.accessToken, userAgent: 'codex-test' });
  const { buffer } = await sdk.marketSkills.downloadSkill('pageel-para-skills-para-skill');
  const zip = new AdmZip(Buffer.from(buffer));
  fs.mkdirSync(dest, { recursive: true });
  for (const entry of zip.getEntries()) {
    if (entry.isDirectory) continue;
    const target = path.join(dest, entry.entryName);
    fs.mkdirSync(path.dirname(target), { recursive: true });
    fs.writeFileSync(target, entry.getData());
  }
  console.log(dest);
})();
